// withRpgActivityID sets the ID field of the mutation.
func withRpgActivityID(id int) rpgactivityOption {
	return func(m *RpgActivityMutation) {
		var (
			err   error
			once  sync.Once
			value *RpgActivity
		)
		m.oldValue = func(ctx context.Context) (*RpgActivity, error) {
			once.Do(func() {
				if m.done {
					err = errors.New("querying old values post mutation is not allowed")
				} else {
					value, err = m.Client().RpgActivity.Get(ctx, id)
				}
			})
			return value, err
		}
		m.id = &id
	}
}

